using System.Collections.Concurrent;
using sv_88283bd295734df9acfc92642fd5fc46.Models;

namespace sv_88283bd295734df9acfc92642fd5fc46.Services;

/// <summary>
/// Singleton store keyed by session ID. Each user gets independent wizard state.
/// In per-page interactivity, scoped services are per-circuit and lost on navigation,
/// so a singleton store with session-based keys is required to persist across pages.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, ApplicationData> _store = new();

    public ApplicationData GetOrCreate(string sessionId)
    {
        return _store.GetOrAdd(sessionId, _ => new ApplicationData());
    }

    public void Remove(string sessionId)
    {
        _store.TryRemove(sessionId, out _);
    }
}

