namespace sv_88283bd295734df9acfc92642fd5fc46.Services;

/// <summary>
/// Ensures every request has a WizardSession cookie for identifying the user's wizard state.
/// </summary>
public class SessionMiddleware
{
    private readonly RequestDelegate _next;
    private const string CookieName = "WizardSession";

    public SessionMiddleware(RequestDelegate next) => _next = next;

    public async Task InvokeAsync(HttpContext context)
    {
        if (!context.Request.Cookies.ContainsKey(CookieName))
        {
            var sessionId = Guid.NewGuid().ToString("N");
            context.Response.Cookies.Append(CookieName, sessionId, new CookieOptions
            {
                HttpOnly = true,
                SameSite = SameSiteMode.Strict,
                MaxAge = TimeSpan.FromHours(24)
            });
            // Also make it available for the current request
            context.Items["WizardSession"] = sessionId;
        }

        await _next(context);
    }
}

