@inherits LayoutComponentBase
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_88283bd295734df9acfc92642fd5fc46.Services.WizardStateStore Store

@* This layout renders statically. It reads the session cookie from HttpContext
   and looks up wizard progress from the singleton store. *@

<div class="container py-4">
    <h2 class="mb-3">Job Application</h2>

    <nav class="mb-4">
        <ol class="list-group list-group-horizontal text-center">
            @for (int i = 0; i < _steps.Length; i++)
            {
                var step = _steps[i];
                var stepNumber = i + 1;
                var isCurrent = step.Path == _currentPath;
                var isCompleted = stepNumber <= _completedStep;
                var cssClass = isCurrent ? "list-group-item active flex-fill"
                    : isCompleted ? "list-group-item list-group-item-success flex-fill"
                    : "list-group-item flex-fill";

                <li class="@cssClass">
                    <a href="@step.Path" class="text-decoration-none @(isCurrent ? "text-white" : "")">
                        Step @stepNumber: @step.Label
                    </a>
                </li>
            }
        </ol>
    </nav>

    <div class="mb-2 text-muted">
        Step @_currentStep of @_steps.Length
    </div>

    <article>
        @Body
    </article>
</div>

@code {
    private record StepInfo(string Path, string Label);

    private static readonly StepInfo[] _steps =
    [
        new("/apply/personal-info", "Personal Info"),
        new("/apply/experience", "Experience"),
        new("/apply/references", "References"),
        new("/apply/review", "Review")
    ];

    private int _completedStep;
    private int _currentStep = 1;
    private string _currentPath = "";

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext!;
        _currentPath = httpContext.Request.Path.Value ?? "";

        for (int i = 0; i < _steps.Length; i++)
        {
            if (_steps[i].Path == _currentPath)
            {
                _currentStep = i + 1;
                break;
            }
        }

        var sessionId = httpContext.Request.Cookies["WizardSession"]
            ?? httpContext.Items["WizardSession"] as string ?? "";

        if (!string.IsNullOrEmpty(sessionId))
        {
            var data = Store.GetOrCreate(sessionId);
            _completedStep = data.CompletedStep;
        }
    }
}

using Microsoft.AspNetCore.Components;
using sv_88283bd295734df9acfc92642fd5fc46.Models;
using sv_88283bd295734df9acfc92642fd5fc46.Services;

namespace sv_88283bd295734df9acfc92642fd5fc46.Components.Pages.Apply;

/// <summary>
/// Base class for wizard pages. Handles bridging the session ID from
/// static prerender (where HttpContext is available) to the interactive phase
/// (where it is not) using PersistentComponentState.
/// </summary>
public abstract class WizardPageBase : ComponentBase, IDisposable
{
    [Inject] private IHttpContextAccessor HttpContextAccessor { get; set; } = default!;
    [Inject] private PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] protected WizardStateStore Store { get; set; } = default!;
    [Inject] protected NavigationManager Navigation { get; set; } = default!;

    protected string SessionId { get; private set; } = "";
    protected ApplicationData AppData { get; private set; } = new();

    private PersistingComponentStateSubscription _subscription;

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionId", SessionId);
            return Task.CompletedTask;
        });

        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            // Prerender phase — HttpContext is available
            SessionId = httpContext.Request.Cookies["WizardSession"]
                ?? httpContext.Items["WizardSession"] as string ?? "";
        }
        else
        {
            // Interactive phase — restore from persisted state
            PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored);
            SessionId = restored ?? "";
        }

        if (!string.IsNullOrEmpty(SessionId))
        {
            AppData = Store.GetOrCreate(SessionId);
        }
    }

    protected void NavigateToStep(string path)
    {
        Navigation.NavigateTo(path);
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

