@page "/apply/personal-info"
@layout ApplyLayout
@rendermode InteractiveServer
@inherits WizardPageBase

<PageTitle>Personal Info - Job Application</PageTitle>

<h3>Personal Information</h3>

<EditForm Model="_model" OnValidSubmit="HandleNext" FormName="personalInfo">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="_model.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <InputText class="form-control" @bind-Value="_model.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    private PersonalInfoData _model = new();

    protected override void OnInitialized()
    {
        base.OnInitialized();
        // Load existing data
        _model = new PersonalInfoData
        {
            Name = AppData.PersonalInfo.Name,
            Email = AppData.PersonalInfo.Email
        };
    }

    private void HandleNext()
    {
        AppData.PersonalInfo.Name = _model.Name;
        AppData.PersonalInfo.Email = _model.Email;
        if (AppData.CompletedStep < 1) AppData.CompletedStep = 1;
        NavigateToStep("/apply/experience");
    }
}

@page "/apply/experience"
@layout ApplyLayout
@rendermode InteractiveServer
@inherits WizardPageBase

<PageTitle>Experience - Job Application</PageTitle>

<h3>Work Experience</h3>

@for (int i = 0; i < _jobs.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between">
            <strong>Job @(index + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="_jobs[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="_jobs[index].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Duration</label>
            <input class="form-control" @bind="_jobs[index].Duration" />
        </div>
    </div>
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex gap-2">
    <button type="button" class="btn btn-secondary" @onclick="GoBack">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    private List<JobEntry> _jobs = [];

    protected override void OnInitialized()
    {
        base.OnInitialized();
        _jobs = AppData.Experience.Jobs
            .Select(j => new JobEntry { Company = j.Company, Title = j.Title, Duration = j.Duration })
            .ToList();
    }

    private void AddJob() => _jobs.Add(new JobEntry());

    private void RemoveJob(int index) => _jobs.RemoveAt(index);

    private void GoBack() => NavigateToStep("/apply/personal-info");

    private void HandleNext()
    {
        AppData.Experience.Jobs = _jobs
            .Select(j => new JobEntry { Company = j.Company, Title = j.Title, Duration = j.Duration })
            .ToList();
        if (AppData.CompletedStep < 2) AppData.CompletedStep = 2;
        NavigateToStep("/apply/references");
    }
}

