@page "/apply/review"
@layout ApplyLayout
@rendermode InteractiveServer
@inherits WizardPageBase

<PageTitle>Review - Job Application</PageTitle>

<h3>Review Your Application</h3>

<div class="card mb-3 p-3">
    <h5>Personal Information</h5>
    <dl class="row mb-0">
        <dt class="col-sm-3">Name</dt>
        <dd class="col-sm-9">@AppData.PersonalInfo.Name</dd>
        <dt class="col-sm-3">Email</dt>
        <dd class="col-sm-9">@AppData.PersonalInfo.Email</dd>
    </dl>
</div>

<div class="card mb-3 p-3">
    <h5>Work Experience</h5>
    @if (AppData.Experience.Jobs.Count == 0)
    {
        <p class="text-muted">No jobs entered.</p>
    }
    else
    {
        @foreach (var job in AppData.Experience.Jobs)
        {
            <div class="border-bottom pb-2 mb-2">
                <strong>@job.Title</strong> at @job.Company <span class="text-muted">(@job.Duration)</span>
            </div>
        }
    }
</div>

<div class="card mb-3 p-3">
    <h5>References</h5>
    @if (AppData.References.Contacts.Count == 0)
    {
        <p class="text-muted">No references entered.</p>
    }
    else
    {
        @foreach (var contact in AppData.References.Contacts)
        {
            <div class="border-bottom pb-2 mb-2">
                <strong>@contact.Name</strong> — @contact.Email <span class="text-muted">(@contact.Relationship)</span>
            </div>
        }
    }
</div>

<div class="d-flex gap-2">
    <button type="button" class="btn btn-secondary" @onclick="GoBack">← Back</button>
    <button type="button" class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3">Application submitted successfully!</div>
}

@code {
    private bool _submitted;

    private void GoBack() => NavigateToStep("/apply/references");

    private void Submit()
    {
        AppData.CompletedStep = 4;
        _submitted = true;
    }
}

